// Séparer le nom et l'extension
const lastDot = filename.lastIndexOf('.');
const name = lastDot > 0 ? filename.slice(0, lastDot) : filename;
const ext = lastDot > 0 ? filename.slice(lastDot) : '';

const normalized = name
  // Normaliser les accents (décomposition Unicode)
  .normalize('NFD')
  // Supprimer les diacritiques
  .replace(/[\u0300-\u036f]/g, '')
  // Convertir en minuscules
  .toLowerCase()
  // Remplacer espaces et underscores par des tirets
  .replace(/[\s_]+/g, '-')
  // Ne garder que lettres, chiffres et tirets
  .replace(/[^a-z0-9-]/g, '')
  // Éviter les tirets multiples
  .replace(/-+/g, '-')
  // Supprimer tirets en début/fin
  .replace(/^-|-$/g, '');

return normalized + ext.toLowerCase();
